import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { tourService } from './services/tourService';
import { authService } from './services/authService';
import Login from './components/Auth/Login';
import Register from './components/Auth/Register';
import './App.css';

function App() {
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
    checkAuthStatus();
    fetchTours();
  }, []);

  const checkAuthStatus = () => {
    if (authService.isLoggedIn()) {
      const userData = authService.getUser();
      setUser(userData);
    }
    setAuthLoading(false);
  };

  const fetchTours = async () => {
    try {
      const response = await tourService.getAllTours();
      if (response.success) {
        setTours(response.data);
      }
    } catch (error) {
      console.error('Error fetching tours:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = (userData) => {
    setUser(userData);
  };

  const handleRegister = (userData) => {
    setUser(userData);
  };

  const handleLogout = () => {
    authService.removeToken();
    setUser(null);
  };

  if (authLoading) {
    return <div>Loading...</div>;
  }

  return (
    <Router>
      <div className="App">
        <header style={{ padding: '10px', borderBottom: '1px solid #ccc', marginBottom: '20px' }}>
          <h1>Tour Management System</h1>
          <nav>
            {user ? (
              <div>
                <span>Welcome, {user.username}!</span>
                <button onClick={handleLogout} style={{ marginLeft: '10px', padding: '5px 10px' }}>
                  Logout
                </button>
              </div>
            ) : (
              <div>
                <a href="/login" style={{ marginRight: '10px' }}>Login</a>
                <a href="/register">Register</a>
              </div>
            )}
          </nav>
        </header>

        <Routes>
          <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
          <Route path="/register" element={!user ? <Register onRegister={handleRegister} /> : <Navigate to="/" />} />
          <Route path="/" element={
            <div>
              <h2>Available Tours ({tours.length})</h2>
              {loading ? (
                <div>Loading tours...</div>
              ) : (
                tours.map((tour) => (
                  <div key={tour._id} style={{ border: '1px solid #ccc', margin: '10px', padding: '10px', borderRadius: '5px' }}>
                    <h3>{tour.title}</h3>
                    <p><strong>City:</strong> {tour.city}</p>
                    <p><strong>Price:</strong> ${tour.price}</p>
                    <p><strong>Distance:</strong> {tour.distance}km</p>
                    <p><strong>Max Group Size:</strong> {tour.maxGroupSize}</p>
                    <p>{tour.desc}</p>
                    {tour.featured && <span style={{ color: 'green', fontWeight: 'bold' }}>⭐ Featured</span>}
                  </div>
                ))
              )}
            </div>
          } />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
